ruleToc.chapterList:
@js:
result=result.match(/\((.*)\)$/);
result=(result)?result[1]:'';
var reg1=new RegExp(/"name":"(.*?)"/g);
var reg2=new RegExp(/"id":(\d+)/g);
var reg3=new RegExp(/"coin":"(\d+)"/g);
var list=[],t;
var bid=java.get('bid');
while((t=reg2.exec(result))){
var id=t[1];
var name=reg1.exec(result)[1];
var vip=reg3.exec(result)[1];
name=((vip==0)?name:'🔒'+name);
list.push({name:name,id:'http://book.qudu99.com/apidata/read?book='+bid+'&curindex='+id+'&index='+id+'&size=1'});
}
list;

